/**
 * Centralized Error Codes for E-Menum Application
 *
 * This file defines all error codes used throughout the application.
 * Error codes are organized by category and mapped to HTTP status codes.
 *
 * Usage:
 * ```typescript
 * import { ErrorCodes, getHttpStatus, isValidErrorCode } from '@/core/exceptions/error-codes';
 *
 * throw new AppException(ErrorCodes.MENU_NOT_FOUND, getHttpStatus(ErrorCodes.MENU_NOT_FOUND));
 * ```
 *
 * @see API_CONTRACTS.md - Section 3.2 Error Codes Catalog
 */

// ============================================
// Error Code Constants
// ============================================

/**
 * Authentication error codes (HTTP 401)
 * Use when authentication is required but not provided or invalid
 */
export const AUTH_ERRORS = {
  /** Missing or invalid authentication token */
  UNAUTHORIZED: 'UNAUTHORIZED',
  /** JWT access token has expired */
  TOKEN_EXPIRED: 'TOKEN_EXPIRED',
  /** Invalid email or password during login */
  INVALID_CREDENTIALS: 'INVALID_CREDENTIALS',
  /** JWT token is malformed or invalid */
  INVALID_TOKEN: 'INVALID_TOKEN',
  /** Refresh token is invalid or expired */
  INVALID_REFRESH_TOKEN: 'INVALID_REFRESH_TOKEN',
  /** Session has been invalidated */
  SESSION_INVALID: 'SESSION_INVALID',
  /** Account is locked due to too many failed attempts */
  ACCOUNT_LOCKED: 'ACCOUNT_LOCKED',
  /** Email verification is required */
  EMAIL_NOT_VERIFIED: 'EMAIL_NOT_VERIFIED',
  /** Password reset token is invalid or expired */
  INVALID_RESET_TOKEN: 'INVALID_RESET_TOKEN',
} as const;

/**
 * Authorization error codes (HTTP 403)
 * Use when user lacks permission for an action
 */
export const AUTHZ_ERRORS = {
  /** User does not have permission for the action */
  FORBIDDEN: 'FORBIDDEN',
  /** Feature requires a higher subscription plan */
  INSUFFICIENT_PLAN: 'INSUFFICIENT_PLAN',
  /** Feature is not enabled for the organization */
  FEATURE_DISABLED: 'FEATURE_DISABLED',
  /** User role does not permit this operation */
  ROLE_NOT_PERMITTED: 'ROLE_NOT_PERMITTED',
  /** Resource access is restricted */
  ACCESS_RESTRICTED: 'ACCESS_RESTRICTED',
  /** IP address is not whitelisted */
  IP_NOT_ALLOWED: 'IP_NOT_ALLOWED',
} as const;

/**
 * Validation error codes (HTTP 400)
 * Use for input validation and bad request scenarios
 */
export const VALIDATION_ERRORS = {
  /** General validation failure with field-level errors */
  VALIDATION_ERROR: 'VALIDATION_ERROR',
  /** Request body contains invalid or malformed JSON */
  INVALID_JSON: 'INVALID_JSON',
  /** General bad request */
  BAD_REQUEST: 'BAD_REQUEST',
  /** Invalid input for a specific field or operation */
  INVALID_INPUT: 'INVALID_INPUT',
  /** Required parameter is missing */
  MISSING_PARAMETER: 'MISSING_PARAMETER',
  /** Parameter value is out of acceptable range */
  PARAMETER_OUT_OF_RANGE: 'PARAMETER_OUT_OF_RANGE',
  /** File upload validation failed */
  INVALID_FILE: 'INVALID_FILE',
  /** File size exceeds maximum limit */
  FILE_TOO_LARGE: 'FILE_TOO_LARGE',
  /** File type is not allowed */
  INVALID_FILE_TYPE: 'INVALID_FILE_TYPE',
  /** Invalid date or date range */
  INVALID_DATE: 'INVALID_DATE',
  /** Invalid email format */
  INVALID_EMAIL: 'INVALID_EMAIL',
  /** Invalid phone number format */
  INVALID_PHONE: 'INVALID_PHONE',
  /** Invalid URL format */
  INVALID_URL: 'INVALID_URL',
  /** Invalid slug format */
  INVALID_SLUG: 'INVALID_SLUG',
  /** Slug contains reserved words */
  RESERVED_SLUG: 'RESERVED_SLUG',
} as const;

/**
 * Resource not found error codes (HTTP 404)
 * Use when a requested resource doesn't exist
 */
export const NOT_FOUND_ERRORS = {
  /** Generic resource not found */
  NOT_FOUND: 'NOT_FOUND',
