  ORGANIZATION_NOT_FOUND: 'ORGANIZATION_NOT_FOUND',
  /** Branch not found */
  BRANCH_NOT_FOUND: 'BRANCH_NOT_FOUND',
  /** Menu not found */
  MENU_NOT_FOUND: 'MENU_NOT_FOUND',
  /** Category not found */
  CATEGORY_NOT_FOUND: 'CATEGORY_NOT_FOUND',
  /** Product not found */
  PRODUCT_NOT_FOUND: 'PRODUCT_NOT_FOUND',
  /** Product variant not found */
  VARIANT_NOT_FOUND: 'VARIANT_NOT_FOUND',
  /** Product modifier not found */
  MODIFIER_NOT_FOUND: 'MODIFIER_NOT_FOUND',
  /** Order not found */
  ORDER_NOT_FOUND: 'ORDER_NOT_FOUND',
  /** Order item not found */
  ORDER_ITEM_NOT_FOUND: 'ORDER_ITEM_NOT_FOUND',
  /** Table not found */
  TABLE_NOT_FOUND: 'TABLE_NOT_FOUND',
  /** Zone not found */
  ZONE_NOT_FOUND: 'ZONE_NOT_FOUND',
  /** QR code not found */
  QR_CODE_NOT_FOUND: 'QR_CODE_NOT_FOUND',
  /** Theme not found */
  THEME_NOT_FOUND: 'THEME_NOT_FOUND',
  /** Media/file not found */
  MEDIA_NOT_FOUND: 'MEDIA_NOT_FOUND',
  /** Notification not found */
  NOTIFICATION_NOT_FOUND: 'NOTIFICATION_NOT_FOUND',
  /** Subscription not found */
  SUBSCRIPTION_NOT_FOUND: 'SUBSCRIPTION_NOT_FOUND',
  /** Plan not found */
  PLAN_NOT_FOUND: 'PLAN_NOT_FOUND',
  /** Invoice not found */
  INVOICE_NOT_FOUND: 'INVOICE_NOT_FOUND',
  /** Session not found */
  SESSION_NOT_FOUND: 'SESSION_NOT_FOUND',
  /** Role not found */
  ROLE_NOT_FOUND: 'ROLE_NOT_FOUND',
  /** Permission not found */
  PERMISSION_NOT_FOUND: 'PERMISSION_NOT_FOUND',
  /** Customer not found */
  CUSTOMER_NOT_FOUND: 'CUSTOMER_NOT_FOUND',
  /** Feedback not found */
  FEEDBACK_NOT_FOUND: 'FEEDBACK_NOT_FOUND',
  /** Allergen not found */
  ALLERGEN_NOT_FOUND: 'ALLERGEN_NOT_FOUND',
  /** Route/endpoint not found */
  ROUTE_NOT_FOUND: 'ROUTE_NOT_FOUND',
} as const;

/**
 * Conflict error codes (HTTP 409)
 * Use when resource already exists or there's a state conflict
 */
export const CONFLICT_ERRORS = {
  /** Generic conflict error */
  CONFLICT: 'CONFLICT',
  /** User with this email already exists */
  USER_ALREADY_EXISTS: 'USER_ALREADY_EXISTS',
  /** Organization with this slug already exists */
  ORGANIZATION_ALREADY_EXISTS: 'ORGANIZATION_ALREADY_EXISTS',
  /** Menu with this slug already exists */
  MENU_ALREADY_EXISTS: 'MENU_ALREADY_EXISTS',
  /** Category with this name already exists in menu */
  CATEGORY_ALREADY_EXISTS: 'CATEGORY_ALREADY_EXISTS',
  /** Product with this slug already exists */
  PRODUCT_ALREADY_EXISTS: 'PRODUCT_ALREADY_EXISTS',
  /** Table with this number already exists in zone */
  TABLE_ALREADY_EXISTS: 'TABLE_ALREADY_EXISTS',
  /** QR code for this resource already exists */
  QR_CODE_ALREADY_EXISTS: 'QR_CODE_ALREADY_EXISTS',
  /** Optimistic lock conflict - resource was modified by another request */
  VERSION_CONFLICT: 'VERSION_CONFLICT',
  /** Operation cannot proceed due to current resource state */
  STATE_CONFLICT: 'STATE_CONFLICT',
  /** Email is already registered */
  EMAIL_ALREADY_REGISTERED: 'EMAIL_ALREADY_REGISTERED',
  /** Slug is already taken */
  SLUG_ALREADY_TAKEN: 'SLUG_ALREADY_TAKEN',
} as const;

/**
 * Business rule error codes (HTTP 422)
 * Use when request is valid but violates business rules
 */
export const BUSINESS_ERRORS = {
  /** Generic unprocessable entity */
  UNPROCESSABLE: 'UNPROCESSABLE',
  /** Cannot delete resource because it has dependencies */
  HAS_DEPENDENCIES: 'HAS_DEPENDENCIES',
  /** Order is in a state that doesn't allow this operation */
  INVALID_ORDER_STATE: 'INVALID_ORDER_STATE',
  /** Invalid order status transition */
  INVALID_STATUS_TRANSITION: 'INVALID_STATUS_TRANSITION',
  /** Product is not available for ordering */
  PRODUCT_UNAVAILABLE: 'PRODUCT_UNAVAILABLE',
  /** Menu is not published */
  MENU_NOT_PUBLISHED: 'MENU_NOT_PUBLISHED',
  /** Cannot modify published menu */
  MENU_IS_PUBLISHED: 'MENU_IS_PUBLISHED',
  /** Subscription is not active */
  SUBSCRIPTION_INACTIVE: 'SUBSCRIPTION_INACTIVE',
  /** Payment is required to proceed */
  PAYMENT_REQUIRED: 'PAYMENT_REQUIRED',
  /** Operation is not allowed in current context */
  OPERATION_NOT_ALLOWED: 'OPERATION_NOT_ALLOWED',
  /** Resource is archived and cannot be modified */
  RESOURCE_ARCHIVED: 'RESOURCE_ARCHIVED',
  /** Cannot delete last owner of organization */
  CANNOT_DELETE_LAST_OWNER: 'CANNOT_DELETE_LAST_OWNER',
  /** Cannot change own role */
  CANNOT_CHANGE_OWN_ROLE: 'CANNOT_CHANGE_OWN_ROLE',
  /** Cart is empty */
  EMPTY_CART: 'EMPTY_CART',
  /** Minimum order amount not met */
  MINIMUM_ORDER_NOT_MET: 'MINIMUM_ORDER_NOT_MET',
} as const;

/**
 * Rate limiting error codes (HTTP 429)
 * Use when request rate limit or quota is exceeded
 */
export const RATE_LIMIT_ERRORS = {
  /** Too many requests in time window */
  RATE_LIMITED: 'RATE_LIMITED',
  /** Plan-based quota exceeded */
  QUOTA_EXCEEDED: 'QUOTA_EXCEEDED',
  /** AI credit balance exhausted */
  AI_CREDITS_EXHAUSTED: 'AI_CREDITS_EXHAUSTED',
  /** Menu limit reached for plan */
  MENU_LIMIT_REACHED: 'MENU_LIMIT_REACHED',
  /** Product limit reached for plan */
  PRODUCT_LIMIT_REACHED: 'PRODUCT_LIMIT_REACHED',
  /** Branch limit reached for plan */
  BRANCH_LIMIT_REACHED: 'BRANCH_LIMIT_REACHED',
  /** User limit reached for plan */
  USER_LIMIT_REACHED: 'USER_LIMIT_REACHED',
  /** Storage limit reached for plan */
  STORAGE_LIMIT_REACHED: 'STORAGE_LIMIT_REACHED',
  /** Daily API call limit reached */
  DAILY_LIMIT_REACHED: 'DAILY_LIMIT_REACHED',
} as const;

/**
 * Server error codes (HTTP 500, 503)
 * Use for unexpected server-side errors
 */
export const SERVER_ERRORS = {
  /** Unexpected internal server error */
  INTERNAL_ERROR: 'INTERNAL_ERROR',
  /** Database operation failed */
  DATABASE_ERROR: 'DATABASE_ERROR',
  /** External service is unavailable */
  SERVICE_UNAVAILABLE: 'SERVICE_UNAVAILABLE',
  /** Cache service error */
  CACHE_ERROR: 'CACHE_ERROR',
  /** File storage operation failed */
  STORAGE_ERROR: 'STORAGE_ERROR',
  /** Email sending failed */
  EMAIL_SEND_FAILED: 'EMAIL_SEND_FAILED',
  /** SMS sending failed */
  SMS_SEND_FAILED: 'SMS_SEND_FAILED',
  /** External API call failed */
  EXTERNAL_API_ERROR: 'EXTERNAL_API_ERROR',
  /** AI service error */
  AI_SERVICE_ERROR: 'AI_SERVICE_ERROR',
  /** Payment processing error */
  PAYMENT_ERROR: 'PAYMENT_ERROR',
  /** Webhook delivery failed */
  WEBHOOK_FAILED: 'WEBHOOK_FAILED',
  /** Background job failed */
  JOB_FAILED: 'JOB_FAILED',
  /** Configuration error */
  CONFIG_ERROR: 'CONFIG_ERROR',
} as const;

/**
 * Module system error codes (HTTP 400, 404)
 * Use for module-related operations
 */
export const MODULE_ERRORS = {
  /** Module not found in system */
  MODULE_NOT_FOUND: 'MODULE_NOT_FOUND',
  /** Module has unmet dependencies */
  MODULE_DEPENDENCY_ERROR: 'MODULE_DEPENDENCY_ERROR',
  /** Core module cannot be disabled */
  CORE_MODULE_PROTECTED: 'CORE_MODULE_PROTECTED',
  /** Module manifest is invalid */
  INVALID_MODULE_MANIFEST: 'INVALID_MODULE_MANIFEST',
  /** Module is already enabled */
  MODULE_ALREADY_ENABLED: 'MODULE_ALREADY_ENABLED',
  /** Module is already disabled */
  MODULE_ALREADY_DISABLED: 'MODULE_ALREADY_DISABLED',
  /** Module activation failed */
  MODULE_ACTIVATION_FAILED: 'MODULE_ACTIVATION_FAILED',
  /** Module is required by other modules */
  MODULE_HAS_DEPENDENTS: 'MODULE_HAS_DEPENDENTS',
  /** Module version is incompatible */
  MODULE_VERSION_INCOMPATIBLE: 'MODULE_VERSION_INCOMPATIBLE',
  /** Module initialization failed */
  MODULE_INIT_FAILED: 'MODULE_INIT_FAILED',
} as const;

/**
 * Multi-tenancy error codes (HTTP 403, 404)
 * Use for tenant isolation violations
 */
export const TENANT_ERRORS = {
  /** Tenant/organization not found */
  TENANT_NOT_FOUND: 'TENANT_NOT_FOUND',
  /** Access to tenant data denied */
  TENANT_ACCESS_DENIED: 'TENANT_ACCESS_DENIED',
  /** Missing tenant context in request */
  TENANT_CONTEXT_MISSING: 'TENANT_CONTEXT_MISSING',
  /** Tenant is suspended */
  TENANT_SUSPENDED: 'TENANT_SUSPENDED',
  /** Tenant subscription expired */
  TENANT_SUBSCRIPTION_EXPIRED: 'TENANT_SUBSCRIPTION_EXPIRED',
  /** Cross-tenant operation not allowed */
  CROSS_TENANT_OPERATION: 'CROSS_TENANT_OPERATION',
} as const;

// ============================================
// Combined Error Codes
// ============================================

/**
 * All error codes combined into a single object
 * Use for type inference and lookup
 */
export const ErrorCodes = {
  ...AUTH_ERRORS,
  ...AUTHZ_ERRORS,
  ...VALIDATION_ERRORS,
  ...NOT_FOUND_ERRORS,
  ...CONFLICT_ERRORS,
  ...BUSINESS_ERRORS,
  ...RATE_LIMIT_ERRORS,
  ...SERVER_ERRORS,
  ...MODULE_ERRORS,
  ...TENANT_ERRORS,
} as const;

/**
 * Type representing all valid error codes
 */
export type ErrorCode = (typeof ErrorCodes)[keyof typeof ErrorCodes];

// ============================================
// HTTP Status Code Mapping
// ============================================

/**
 * Maps error codes to their corresponding HTTP status codes
 * Follows REST conventions and API_CONTRACTS.md specification
 */
