  [VALIDATION_ERRORS.MISSING_PARAMETER]: 400,
  [VALIDATION_ERRORS.PARAMETER_OUT_OF_RANGE]: 400,
  [VALIDATION_ERRORS.INVALID_FILE]: 400,
  [VALIDATION_ERRORS.FILE_TOO_LARGE]: 400,
  [VALIDATION_ERRORS.INVALID_FILE_TYPE]: 400,
  [VALIDATION_ERRORS.INVALID_DATE]: 400,
  [VALIDATION_ERRORS.INVALID_EMAIL]: 400,
  [VALIDATION_ERRORS.INVALID_PHONE]: 400,
  [VALIDATION_ERRORS.INVALID_URL]: 400,
  [VALIDATION_ERRORS.INVALID_SLUG]: 400,
  [VALIDATION_ERRORS.RESERVED_SLUG]: 400,

  // Not Found (404)
  [NOT_FOUND_ERRORS.NOT_FOUND]: 404,
  [NOT_FOUND_ERRORS.USER_NOT_FOUND]: 404,
  [NOT_FOUND_ERRORS.ORGANIZATION_NOT_FOUND]: 404,
